module top_module(
    input wire clk,
    input wire [13:0] width,
    output reg pulse
);reg [13:0] counter = 0;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    counter <= counter + 1;
    if (counter < width) pulse <= 1'b1;
    else pulse <= 1'b0;
  end
endmodule
